//                   pod=~"ingest-.*"
//               }
//             ) by (pod)
//             /
//             sum(
//               cluster:namespace:pod_cpu:active:kube_pod_container_resource_requests{
//                       namespace=~"(axiom|cloud).*",
//                       pod=~"ingest-.*",
//                       resource="cpu"}
//              ) by (pod)
//         ),
//         "service", "$1", "pod", "(.+)-.+-.+"
//     )
// ) by (service)

// note node_namespace_pod_container:container_cpu_usage_seconds_total:sum_irate are pre-computed
